@include make-grid-columns using ($infix)
    @if $infix != ''
      .v-col-#{$infix}
        --v-col-is-size: #{$false}
        --v-col-is-auto: #{$false}
        --v-col-is-grow: #{$true}

    .v-col--cols#{$infix}-auto
      --v-col-is-size: #{$false}
      --v-col-is-auto: #{$true}
      --v-col-is-grow: #{$false}

    @for $i from 1 through settings.$grid-columns
      .v-col--cols#{$infix}-#{$i}
        --v-col-size: #{$i}
        --v-col-is-size: #{$true}
        --v-col-is-auto: #{$false}
        --v-col-is-grow: #{$false}
        --v-col-size-columns: var(--v-col-size-base#{$infix}, var(--v-row-columns))

    @for $i from 0 through settings.$grid-columns - 1
      @if not ($infix == "" and $i == 0) // skip useless .v-col-offset-0
        .v-col--offset#{$infix}-#{$i}
          --v-col-offset: #{$i}
          --v-col-offset-columns: var(--v-col-offset-base#{$infix}, var(--v-row-columns))

@for $toc_level from 1 through 10
    .toctree-l#{$toc_level}.current .toctree-l#{$toc_level + 1}
      @extend %hide_show_toctree_ul

    @if $toc_level > 1
      li.toctree-l#{$toc_level}
        a
          @extend %toctree_link_color
        &.current
          > a
            padding: ($gutter / 4) ($gutter * ($toc_level - 1 + 0.5))

          li.toctree-l#{$toc_level + 1}  > a
            @extend %display_current_toctree_element
            padding: ($gutter / 4) ($gutter * ($toc_level + 0.5))
            padding-right: $gutter
        a:hover span.toctree-expand
          @extend %toctree_hover_link_color
    @if $toc_level > 2 and $toc_level < 5
      li.toctree-l#{$toc_level}
        @extend %shrink_toctree_element

@each $name2, $size2 in $sizes
      @if $size >= $size2
        $name2c: "-#{$name2}"
        $noProcNotZero2: ($size2 > 0)

        @for $i from 0 through $flex-cols
          $ic: string.quote('' + $i)
          $internal-size: toFixed(math.percentage(math.div($i, $flex-cols)), 10000)

          #{str-fr('.row<name>', $name)}
            #{str-fe('> .col<name>-<i>', $name2c, $noProcNotZero2, $ic)}
              height: auto
              width: $internal-size
            #{str-fe('> .offset<name>-<i>', $name2c, $noProcNotZero2, $ic)}
              margin-left: $internal-size

          #{str-fr('.column<name>', $name)}
            #{str-fe('> .col<name>-<i>', $name2c, $noProcNotZero2, $ic)}
              height: $internal-size
              width: auto
